using UnityEngine;

public class PolishPass : MonoBehaviour
{
    [Header("Audio")]
    public AudioClip jumpSound;
    public AudioClip coinSound;
    public AudioClip hitSound;
    public AudioClip deathSound;
    public AudioClip winSound;
    public AudioClip backgroundMusic;

    [Header("Particles")]
    public ParticleSystem coinParticles;
    public ParticleSystem jumpParticles;
    public ParticleSystem deathParticles;
    public ParticleSystem winParticles;

    private AudioSource audioSource;

    void Start()
    {
        audioSource = GetComponent<AudioSource>();
        if (audioSource == null)
            audioSource = gameObject.AddComponent<AudioSource>();

        // Start background music
        if (backgroundMusic != null)
        {
            audioSource.clip = backgroundMusic;
            audioSource.loop = true;
            audioSource.Play();
        }

        Debug.Log("Polish pass started!");
    }

    void Update()
    {
        // Test sounds with keys
        if (Input.GetKeyDown(KeyCode.Alpha1)) PlayJump();
        if (Input.GetKeyDown(KeyCode.Alpha2)) PlayCoin();
        if (Input.GetKeyDown(KeyCode.Alpha3)) PlayHit();
        if (Input.GetKeyDown(KeyCode.Alpha4)) PlayDeath();
        if (Input.GetKeyDown(KeyCode.Alpha5)) PlayWin();

        // Test particles with keys
        if (Input.GetKeyDown(KeyCode.Q)) SpawnCoinParticles();
        if (Input.GetKeyDown(KeyCode.W)) SpawnJumpParticles();
        if (Input.GetKeyDown(KeyCode.E)) SpawnDeathParticles();
        if (Input.GetKeyDown(KeyCode.R)) SpawnWinParticles();
    }

    // --- Sound methods ---

    public void PlayJump()
    {
        if (jumpSound != null)
        {
            audioSource.PlayOneShot(jumpSound, 0.8f);
            SpawnJumpParticles();
        }
    }

    public void PlayCoin()
    {
        if (coinSound != null)
        {
            audioSource.PlayOneShot(coinSound, 0.6f);
            SpawnCoinParticles();
        }
    }

    public void PlayHit()
    {
        if (hitSound != null)
        {
            audioSource.PlayOneShot(hitSound, 0.9f);
            // Screen shake
            if (ScreenShake.Instance != null)
                ScreenShake.Instance.Shake(0.2f, 0.1f);
        }
    }

    public void PlayDeath()
    {
        if (deathSound != null)
        {
            audioSource.PlayOneShot(deathSound, 1f);
            SpawnDeathParticles();
            if (ScreenShake.Instance != null)
                ScreenShake.Instance.Shake(0.5f, 0.2f);
        }
    }

    public void PlayWin()
    {
        if (winSound != null)
        {
            audioSource.PlayOneShot(winSound, 1f);
            SpawnWinParticles();
            if (ScreenShake.Instance != null)
                ScreenShake.Instance.Shake(0.3f, 0.1f);
        }
    }

    // --- Particle methods ---

    void SpawnCoinParticles()
    {
        if (coinParticles != null)
        {
            coinParticles.Play();
        }
    }

    void SpawnJumpParticles()
    {
        if (jumpParticles != null)
        {
            jumpParticles.Play();
        }
    }

    void SpawnDeathParticles()
    {
        if (deathParticles != null)
        {
            deathParticles.Play();
        }
    }

    void SpawnWinParticles()
    {
        if (winParticles != null)
        {
            winParticles.Play();
        }
    }

    // --- Audio settings ---

    public void SetVolume(float volume)
    {
        audioSource.volume = Mathf.Clamp01(volume);
    }

    public void ToggleMusic(bool enabled)
    {
        audioSource.mute = !enabled;
    }
}

