using UnityEngine;

public class PolishError : MonoBehaviour
{
    void Start()
    {
        // Forgetting to check if AudioClip exists
        audioSource.PlayOneShot(jumpSound);  // NullReferenceException

        // Forgetting to check if ParticleSystem exists
        particleSystem.Play();  // NullReferenceException
    }
}

phase2.explanation:
You need to check if audio clips and particle systems exist before using them.

**The fix:**
```csharp
if (jumpSound != null)
    audioSource.PlayOneShot(jumpSound);

if (particleSystem != null)
    particleSystem.Play();
```

**Sharp-chan says:**
"Always check if assets exist before using them."
